Set-StrictMode -Version 2.0
function Test-GodModeJsonLite { param([string]$Path,[string[]]$RequiredKeys=@()) $r=@{path=$Path;ok=$false;errors=@()}; if(-not(Test-Path $Path)){ $r.errors+='missing'; return $r }; try{$o=Get-Content $Path -Raw -Encoding UTF8|ConvertFrom-Json}catch{$r.errors+='json_parse'; return $r}; foreach($k in $RequiredKeys){ if(-not($o.PSObject.Properties.Name -contains $k)){ $r.errors+="missing_key:$k" } }; $r.ok=($r.errors.Count -eq 0); $r }
function Get-GodModeSchemaRequiredKeys { param([string]$Kind) switch($Kind){ 'mission'{@('schema_version','id','role','task','mode','created_at')} 'result'{@('schema_version','mission_id','agent_role','status','files_touched','commands_run','validation_results','verified_claims','unverified_claims','rejected_claims','proof_bundle','summary','created_at')} 'health'{@('schema_version','updated_at','status','degraded_reasons','blockers')} default{@('schema_version')} } }
